// /api/videos — Pages Function
// Lists every video in the R2 bucket, grouped by top-level folder (category).

const VIDEO_EXTS = ['mp4', 'webm', 'mov', 'avi', 'mkv'];

const CORS_HEADERS = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type',
};

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data, null, 2), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...CORS_HEADERS,
    },
  });
}

function isVideo(key) {
  const ext = key.split('.').pop().toLowerCase();
  return VIDEO_EXTS.includes(ext);
}

// Build a public URL from the R2 base and the object key,
// encoding each path segment individually.
function buildPublicUrl(publicBase, key) {
  const encoded = key
    .split('/')
    .map(segment => encodeURIComponent(segment))
    .join('/');
  return `${publicBase}/${encoded}`;
}

// List every object under a given prefix, paginating through all cursors.
async function listAllObjects(bucket, prefix) {
  const objects = [];
  let cursor;

  do {
    const listing = await bucket.list({
      prefix,
      cursor,
      limit: 1000,
      include: ['customMetadata'],
    });
    objects.push(...listing.objects);
    cursor = listing.truncated ? listing.cursor : undefined;
  } while (cursor);

  return objects;
}

export async function onRequestOptions() {
  return new Response(null, { headers: CORS_HEADERS });
}

export async function onRequestGet(context) {
  const { env } = context;

  try {
    // --- Validate bindings -----------------------------------------------
    if (!env.MEDIA_BUCKET) {
      return jsonResponse(
        { error: 'R2 bucket binding "MEDIA_BUCKET" is not configured.' },
        500,
      );
    }

    const publicBase = (env.R2_PUBLIC_URL || '').replace(/\/+$/, '');
    if (!publicBase) {
      return jsonResponse(
        { error: 'R2_PUBLIC_URL environment variable is not configured.' },
        500,
      );
    }

    // --- Step 1: Discover all top-level folders --------------------------
    const folders = [];
    const rootObjects = [];
    let cursor;

    do {
      const listing = await env.MEDIA_BUCKET.list({ delimiter: '/', cursor });
      folders.push(...(listing.delimitedPrefixes || []));
      rootObjects.push(...(listing.objects || []));
      cursor = listing.truncated ? listing.cursor : undefined;
    } while (cursor);

    // --- Step 2: Collect videos from each folder -------------------------
    const categories = {};

    for (const folder of folders) {
      const categoryName = folder.replace(/\/+$/, '');
      const objects = await listAllObjects(env.MEDIA_BUCKET, folder);

      const videos = objects
        .filter(obj => isVideo(obj.key))
        .map(obj => {
          const filename = obj.key.split('/').pop();
          return {
            name: decodeURIComponent(filename),
            url: buildPublicUrl(publicBase, obj.key),
            size: obj.size,
            uploaded: obj.uploaded ? obj.uploaded.toISOString() : null,
          };
        });

      if (videos.length > 0) {
        // Sort newest first
        videos.sort(
          (a, b) => new Date(b.uploaded || 0) - new Date(a.uploaded || 0),
        );
        categories[categoryName] = videos;
      }
    }

    // --- Step 3: Collect root-level videos (no folder) ------------------
    const rootVideos = rootObjects
      .filter(obj => isVideo(obj.key))
      .map(obj => ({
        name: decodeURIComponent(obj.key),
        url: buildPublicUrl(publicBase, obj.key),
        size: obj.size,
        uploaded: obj.uploaded ? obj.uploaded.toISOString() : null,
      }));

    if (rootVideos.length > 0) {
      rootVideos.sort(
        (a, b) => new Date(b.uploaded || 0) - new Date(a.uploaded || 0),
      );
      categories['root'] = rootVideos;
    }

    // --- Done ------------------------------------------------------------
    const total = Object.values(categories).reduce(
      (sum, vids) => sum + vids.length,
      0,
    );

    return jsonResponse({ total, categories });
  } catch (error) {
    return jsonResponse(
      {
        error: 'Failed to list videos from R2 bucket.',
        message: error.message,
      },
      500,
    );
  }
}

// ============================================
// SCROLL RESTORATION
// Prevent browser from restoring scroll position on reload
// ============================================
if ('scrollRestoration' in history) {
  history.scrollRestoration = 'manual';
}

// ============================================
// DOM REFERENCES
// ============================================
const year = document.querySelector('#year');
const mediaOpeners = document.querySelectorAll('[data-lightbox-src]');
const imageModal = document.querySelector('#image-modal');
const modalImage = imageModal ? imageModal.querySelector('img') : null;
const modalClose = imageModal ? imageModal.querySelector('.modal-close') : null;
const navToggle = document.querySelector('#nav-toggle');
const navMenu = document.querySelector('#nav-menu');
const navLinks = document.querySelectorAll('.nav-link');
const bottomNav = document.querySelector('#bottom-nav');
const bottomNavItems = document.querySelectorAll('.bottom-nav-item');
const menuBtn = document.querySelector('#menu-btn');
const menuPanel = document.querySelector('#menu-panel');
const menuClose = document.querySelector('#menu-close');
const menuItems = document.querySelectorAll('.menu-item');
const pageViews = document.querySelectorAll('.page-view');
const navItems = document.querySelectorAll('[data-nav]');

// ============================================
// UTILITIES
// ============================================
function throttle(func, limit) {
  let inThrottle;
  return function() {
    const args = arguments;
    const context = this;
    if (!inThrottle) {
      func.apply(context, args);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  };
}

function debounce(func, wait) {
  let timeout;
  return function(...args) {
    const later = () => {
      clearTimeout(timeout);
      func(...args);
    };
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
  };
}

function pauseAllVideos() {
  document.querySelectorAll('video').forEach(video => video.pause());
}

// Attach loading-state event handlers to a reel card's video element
function initVideoLoadingHandlers(card, video) {
  if (!card || !video) return;

  video.addEventListener('loadstart', () => card.classList.add('loading'));
  video.addEventListener('loadedmetadata', () => card.classList.remove('loading'));
  video.addEventListener('loadeddata', () => card.classList.remove('loading'));
  video.addEventListener('canplay', () => card.classList.remove('loading'));
  video.addEventListener('waiting', () => card.classList.add('loading'));
  video.addEventListener('playing', () => card.classList.remove('loading'));

  // Fallback: remove loading state after 5s (iOS)
  setTimeout(() => card.classList.remove('loading'), 5000);
}

// Category labels for video overlays
const categoryLabels = {
  ugc: 'UGC',
  shoting: 'Shooting',
  stores: 'Stores',
  events: 'Events',
  services: 'Services'
};

// ============================================
// YEAR
// ============================================
if (year) {
  year.textContent = new Date().getFullYear();
}

// ============================================
// IMAGE PREVIEW / LIGHTBOX
// ============================================
function openImagePreview(opener) {
  if (!imageModal || !modalImage) return;

  modalImage.src = opener.dataset.lightboxSrc;
  modalImage.alt = opener.dataset.lightboxAlt || '';
  imageModal.classList.add('active');
  imageModal.setAttribute('aria-hidden', 'false');
  document.body.classList.add('modal-open');
}

function closeImagePreview() {
  if (!imageModal || !modalImage) return;

  imageModal.classList.remove('active');
  imageModal.setAttribute('aria-hidden', 'true');
  document.body.classList.remove('modal-open');
  modalImage.removeAttribute('src');
  modalImage.alt = '';
}

mediaOpeners.forEach(opener => {
  opener.addEventListener('click', () => openImagePreview(opener));
});

if (modalClose) {
  modalClose.addEventListener('click', closeImagePreview);
}

if (imageModal) {
  imageModal.addEventListener('click', event => {
    if (event.target === imageModal) closeImagePreview();
  });
}

document.addEventListener('keydown', event => {
  if (event.key === 'Escape') closeImagePreview();
});

// ============================================
// /api/videos — R2 MEDIA (Pages Function)
// ============================================

// In-memory cache — 5-minute TTL
let mediaCache = null;
let mediaCacheTime = 0;
const MEDIA_CACHE_TTL = 5 * 60 * 1000; // 5 minutes

async function fetchAllMedia() {
  if (mediaCache && (Date.now() - mediaCacheTime) < MEDIA_CACHE_TTL) {
    return mediaCache;
  }

  try {
    const response = await fetch('/api/videos');
    if (!response.ok) throw new Error('/api/videos returned ' + response.status);
    const data = await response.json();

    // Transform API response to the format expected by renderVideoCategory.
    // API returns: { categories: { "UGC": [{ name, url, size, uploaded }] } }
    // We need:     { ugc: [{ video: url, ... }] }
    const result = {};
    const categories = data.categories || {};

    for (const [folderName, videos] of Object.entries(categories)) {
      const match = videoCategories.find(
        cat => cat.folder.toLowerCase() === folderName.toLowerCase()
      );
      const slug = match ? match.slug : folderName.toLowerCase();
      result[slug] = videos.map(v => ({
        video: v.url,
        title: v.name,
        category: slug
      }));
    }

    mediaCache = result;
    mediaCacheTime = Date.now();
    return mediaCache;
  } catch (err) {
    console.error('Failed to fetch videos from /api/videos:', err);
    return {};
  }
}

function createReelCard(item) {
  const card = document.createElement('article');
  card.className = 'reel-card';
  card.innerHTML =
    '<video controls controlsList="nodownload noplaybackrate" disablePictureInPicture playsinline preload="metadata">' +
      '<source src="' + item.video + '" type="video/mp4">' +
    '</video>';
  return card;
}

// Lazy-load video sources via IntersectionObserver — avoids loading
// metadata for dozens of off-screen videos on category pages
const lazyVideoObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      const source = entry.target.querySelector('source');
      if (source && source.dataset.src) {
        source.src = source.dataset.src;
        source.removeAttribute('data-src');
        entry.target.load();
      }
      lazyVideoObserver.unobserve(entry.target);
    }
  });
}, { rootMargin: '300px 0px', threshold: 0.01 });

const videoCategories = [
  { slug: 'ugc',      folder: 'UGC',      json: 'ugc.json',      homeId: 'home-grid-ugc',      catId: 'grid-cat-ugc',      panel: 'ugc' },
  { slug: 'shoting',  folder: 'Shooting', json: 'shoting.json',  homeId: 'home-grid-shoting',  catId: 'grid-cat-shoting',  panel: 'shoting' },
  { slug: 'stores',   folder: 'Stores',   json: 'stores.json',   homeId: 'home-grid-stores',   catId: 'grid-cat-stores',   panel: 'stores' },
  { slug: 'events',   folder: 'Events',   json: 'events.json',   homeId: 'home-grid-events',   catId: 'grid-cat-events',   panel: 'events' },
  { slug: 'services', folder: 'Services', json: 'services.json', homeId: 'home-grid-services', catId: 'grid-cat-services', panel: 'services' }
];

// Render from /api/videos data (in-memory cache)
function renderVideoCategory(slug, containerId, panel, limit) {
  const grid = document.getElementById(containerId);
  if (!grid || !mediaCache) return;

  const items = mediaCache[slug] || [];
  const list = limit ? items.slice(0, limit) : items;

  const fragment = document.createDocumentFragment();

  list.forEach(item => {
    const card = createReelCard(item);
    fragment.appendChild(card);

    const video = card.querySelector('video');
    initVideoLoadingHandlers(card, video);

    card.classList.add('reveal-scale');
    const delay = Math.min(Math.floor(fragment.children.length / 3), 5);
    card.classList.add('reveal-delay-' + (delay + 1));
    revealObserver.observe(card);
  });

  grid.innerHTML = '';
  grid.appendChild(fragment);

  enhanceReelCards();
  forceActivateRevealCards(grid);
}

// Fallback: load from local JSON files
async function loadVideoCategory(jsonFile, containerId, panel, limit) {
  const grid = document.getElementById(containerId);
  if (!grid) return;

  try {
    const response = await fetch('data/' + jsonFile);
    const items = await response.json();

    const list = limit
      ? items.filter(v => v.featured).slice(0, limit)
      : items;

    const fragment = document.createDocumentFragment();

    list.forEach(item => {
      const card = createReelCard(item);
      fragment.appendChild(card);

      const video = card.querySelector('video');
      initVideoLoadingHandlers(card, video);

      card.classList.add('reveal-scale');
      const delay = Math.min(Math.floor(fragment.children.length / 3), 5);
      card.classList.add('reveal-delay-' + (delay + 1));
      revealObserver.observe(card);
    });

    grid.innerHTML = '';
    grid.appendChild(fragment);

    enhanceReelCards();
    forceActivateRevealCards(grid);
  } catch (err) {
    console.error('Failed to load ' + jsonFile + ':', err);
  }
}

// Shared helper: force-activate reveal cards already in viewport (iOS Safari fix)
function forceActivateRevealCards(grid) {
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      const vh = window.innerHeight || document.documentElement.clientHeight;
      grid.querySelectorAll('.reveal-scale:not(.active)').forEach(el => {
        const rect = el.getBoundingClientRect();
        if (rect.top < vh && rect.bottom > 0) {
          el.classList.add('active');
        }
      });
    });
  });
}

// Orchestrator: try /api/videos first, fall back to local JSON per category
async function loadVideoCategories() {
  const apiData = await fetchAllMedia();

  videoCategories.forEach(cat => {
    const hasApiData = apiData && apiData[cat.slug] && apiData[cat.slug].length > 0;

    if (hasApiData) {
      // API has data — render from cache
      renderVideoCategory(cat.slug, cat.homeId, cat.panel, 3);
      renderVideoCategory(cat.slug, cat.catId, cat.panel + '-full');
    } else {
      // API failed or empty — fall back to local JSON
      loadVideoCategory(cat.json, cat.homeId, cat.panel, 3);
      loadVideoCategory(cat.json, cat.catId, cat.panel + '-full');
    }
  });
}

// ============================================
// VIDEO SEARCH
// ============================================
let searchIndex = null;

async function getSearchIndex() {
  if (searchIndex) return searchIndex;

  const data = await fetchAllMedia();
  searchIndex = [];

  if (data && Object.keys(data).length > 0) {
    for (const [slug, items] of Object.entries(data)) {
      items.forEach(item => {
        searchIndex.push({
          title: item.title || '',
          video: item.video,
          category: slug
        });
      });
    }
    return searchIndex;
  }

  // Fallback: fetch all local JSON files
  const results = await Promise.all(
    videoCategories.map(async cat => {
      try {
        const res = await fetch('data/' + cat.json);
        const items = await res.json();
        return items.map(item => ({
          title: item.title || '',
          video: item.video,
          category: cat.slug
        }));
      } catch {
        return [];
      }
    })
  );

  searchIndex = results.flat();
  return searchIndex;
}

function renderSearchResults(query) {
  const resultsContainer = document.getElementById('video-search-results');
  const grid = document.getElementById('search-results-grid');
  const countEl = document.getElementById('search-results-count');
  const noResultsEl = document.getElementById('search-no-results');
  const featuredPreviews = document.querySelectorAll('.featured-preview');

  if (!resultsContainer || !grid) return;

  if (!query || query.trim() === '') {
    resultsContainer.hidden = true;
    if (noResultsEl) noResultsEl.hidden = true;
    featuredPreviews.forEach(el => el.style.display = '');
    return;
  }

  const q = query.toLowerCase().trim();
  const results = searchIndex.filter(item =>
    (item.title || '').toLowerCase().includes(q)
  );

  featuredPreviews.forEach(el => el.style.display = 'none');
  resultsContainer.hidden = false;

  if (countEl) {
    countEl.textContent = results.length + ' result' + (results.length !== 1 ? 's' : '') + ' for "' + query.trim() + '"';
  }

  grid.innerHTML = '';

  if (results.length === 0) {
    if (noResultsEl) noResultsEl.hidden = false;
    return;
  }

  if (noResultsEl) noResultsEl.hidden = true;

  const fragment = document.createDocumentFragment();

  results.forEach(item => {
    const card = createReelCard(item);
    fragment.appendChild(card);

    const video = card.querySelector('video');
    initVideoLoadingHandlers(card, video);

    card.classList.add('reveal-scale');
    const delay = Math.min(Math.floor(fragment.children.length / 3), 5);
    card.classList.add('reveal-delay-' + (delay + 1));
    revealObserver.observe(card);
  });

  grid.appendChild(fragment);
  enhanceReelCards();
  forceActivateRevealCards(grid);

  // Set correct category tag per card (enhanceReelCards uses grid's data-panel)
  grid.querySelectorAll('.reel-card').forEach((card, i) => {
    const tag = card.querySelector('.reel-tag');
    if (tag) {
      tag.textContent = categoryLabels[results[i].category] || results[i].category;
    }
  });
}

function initVideoSearch() {
  const input = document.getElementById('video-search-input');
  if (!input) return;

  const debouncedSearch = debounce(async function() {
    await getSearchIndex();
    renderSearchResults(input.value);
  }, 200);

  input.addEventListener('input', debouncedSearch);
}

// ============================================
// MOBILE NAVIGATION TOGGLE
// ============================================
if (navToggle && navMenu) {
  navToggle.addEventListener('click', () => {
    const isActive = navToggle.classList.toggle('active');
    navMenu.classList.toggle('active');
    navToggle.setAttribute('aria-expanded', String(isActive));
    navToggle.setAttribute('aria-label', isActive ? 'إغلاق القائمة' : 'فتح القائمة');
  });

  navLinks.forEach(link => {
    link.addEventListener('click', () => {
      navMenu.classList.remove('active');
      navToggle.classList.remove('active');
      navToggle.setAttribute('aria-expanded', 'false');
      navToggle.setAttribute('aria-label', 'فتح القائمة');
    });
  });

  document.addEventListener('click', event => {
    if (!navToggle.contains(event.target) && !navMenu.contains(event.target)) {
      navMenu.classList.remove('active');
      navToggle.classList.remove('active');
      navToggle.setAttribute('aria-expanded', 'false');
      navToggle.setAttribute('aria-label', 'فتح القائمة');
    }
  });
}

// ============================================
// ACTIVE NAV LINK ON SCROLL
// ============================================
function updateActiveNavLink() {
  const sections = document.querySelectorAll('section[id], main[id], footer[id]');
  const scrollPosition = window.scrollY + 100;

  sections.forEach(section => {
    const sectionTop = section.offsetTop;
    const sectionHeight = section.offsetHeight;
    const sectionId = section.getAttribute('id');

    if (scrollPosition >= sectionTop && scrollPosition < sectionTop + sectionHeight) {
      navLinks.forEach(link => {
        link.classList.remove('active');
        if (link.getAttribute('href') === `#${sectionId}`) {
          link.classList.add('active');
        }
      });
    }
  });
}

window.addEventListener('scroll', throttle(updateActiveNavLink, 100), { passive: true });

// ============================================
// MENU PANEL
// ============================================
function closeMenu() {
  if (!menuPanel) return;
  menuPanel.classList.remove('active');
  menuPanel.setAttribute('aria-hidden', 'true');
  document.body.style.overflow = '';
  document.body.style.touchAction = '';
}

if (menuBtn && menuPanel) {
  menuBtn.addEventListener('click', () => {
    menuPanel.classList.add('active');
    menuPanel.setAttribute('aria-hidden', 'false');
    document.body.style.overflow = 'hidden';
    document.body.style.touchAction = 'none';
  });

  if (menuClose) {
    menuClose.addEventListener('click', closeMenu);
  }

  menuItems.forEach(item => {
    item.addEventListener('click', closeMenu);
  });

  menuPanel.addEventListener('click', e => {
    if (e.target === menuPanel) closeMenu();
  });

  document.addEventListener('keydown', e => {
    if (e.key === 'Escape' && menuPanel.classList.contains('active')) {
      closeMenu();
    }
  });
}

// ============================================
// BOTTOM NAVIGATION
// Click handler: active state toggle + ripple effect
// ============================================
bottomNavItems.forEach(item => {
  item.addEventListener('click', function(e) {
    bottomNavItems.forEach(i => i.classList.remove('active'));
    this.classList.add('active');

    // Ripple effect
    const ripple = document.createElement('span');
    ripple.className = 'ripple';
    const rect = this.getBoundingClientRect();
    ripple.style.left = (e.clientX - rect.left) + 'px';
    ripple.style.top = (e.clientY - rect.top) + 'px';
    this.appendChild(ripple);
    setTimeout(() => ripple.remove(), 600);
  });
});

// ============================================
// DYNAMIC SEO META UPDATES
// ============================================
const BASE_URL = 'https://abdellahafkhar7-a11y.github.io/photographyportfolio';
const DEFAULT_TITLE = 'Photography Pixel | وكالة تصوير وتسويق رقمي في أيت ملول - أكادير';
const DEFAULT_DESC = 'Photography Pixel: وكالة تصوير وتسويق رقمي متخصصة في صناعة المحتوى، تصوير المنتجات، المحلات التجارية، فيديوهات UGC والأعراس في أيت ملول - أكادير.';

const pageMeta = {
  'home':            { title: DEFAULT_TITLE, desc: DEFAULT_DESC, crumb: 'Home' },
  'home-portfolio':  { title: 'Portfolio | Photography Pixel', desc: 'استعرض أحدث أعمالنا الإبداعية: فيديوهات UGC، تصوير، محلات تجارية، أعراس وخدمات احترافية في أيت ملول - أكادير.', crumb: 'Portfolio' },
  'home-contact':    { title: 'Contact | Photography Pixel', desc: 'تواصل مع وكالة Photography Pixel لخدمات التصوير والتسويق الرقمي في أيت ملول - أكادير. واتساب، إنستغرام، بريد إلكتروني.', crumb: 'Contact' },
  'cat-ugc':         { title: 'UGC Videos | Photography Pixel', desc: 'مجموعة فيديوهات UGC (محتوى المستخدمين) من وكالة Photography Pixel — محتوى إبداعي احترافي للمنتجات والعلامات التجارية.', crumb: 'UGC Videos' },
  'cat-shoting':     { title: 'Shooting Videos | Photography Pixel', desc: 'مجموعة أعمال التصوير الاحترافي من وكالة Photography Pixel — تصوير منتجات، شخصي، وملابس.', crumb: 'Shooting' },
  'cat-stores':      { title: 'Store Videos | Photography Pixel', desc: 'فيديوهات تصوير المحلات التجارية من وكالة Photography Pixel — محتوى بصري جذاب للمتاجر والمحلات.', crumb: 'Stores' },
  'cat-events':      { title: 'Event Videos | Photography Pixel', desc: 'تصوير الأعراس والمناسبات من وكالة Photography Pixel — تغطية كاملة للأحداث بجودة سينمائية.', crumb: 'Events' },
  'cat-services':    { title: 'Service Videos | Photography Pixel', desc: 'فيديوهات الخدمات الاحترافية من وكالة Photography Pixel — محتوى تسويقي لخدمات الشركات والمؤسسات.', crumb: 'Services' },
  'models':          { title: 'Models | Photography Pixel', desc: 'تعرف على موديلات الاستوديو المتاحة للحجز من وكالة Photography Pixel في أيت ملول - أكادير.', crumb: 'Models' },
  'media-buyer':     { title: 'Media Buyer | Photography Pixel', desc: 'معرض الحملات الإعلانية وأدائها من وكالة Photography Pixel — نتائج قياسية على منصات التواصل الاجتماعي.', crumb: 'Media Buyer' },
  'equipment':       { title: 'Equipment | Photography Pixel', desc: 'تعرف على معدات الاستوديو الاحترافية المستخدمة في وكالة Photography Pixel.', crumb: 'Equipment' },
  'voiceover':       { title: 'Voice Over | Photography Pixel', desc: 'خدمات التعليق الصوتي الاحترافي بالعربية من وكالة Photography Pixel — للإعلانات، الوثائقيات، والمحتوى المؤسسي.', crumb: 'Voice Over' }
};

function updatePageMeta(pageName) {
  const meta = pageMeta[pageName] || pageMeta['home'];

  // Title
  document.title = meta.title;

  // Description
  setMetaContent('meta[name="description"]', meta.desc);

  // Open Graph
  setMetaContent('meta[property="og:title"]', meta.title);
  setMetaContent('meta[property="og:description"]', meta.desc);
  setMetaContent('meta[property="og:url"]', BASE_URL + '/');

  // Twitter
  setMetaContent('meta[name="twitter:title"]', meta.title);
  setMetaContent('meta[name="twitter:description"]', meta.desc);

  // Canonical
  let canonical = BASE_URL + '/';
  if (pageName === 'home-portfolio') canonical = BASE_URL + '/#portfolio';
  else if (pageName === 'home-contact') canonical = BASE_URL + '/#contact';
  const canonicalEl = document.querySelector('link[rel="canonical"]');
  if (canonicalEl) canonicalEl.setAttribute('href', canonical);

  // BreadcrumbList JSON-LD
  const breadcrumbScripts = document.querySelectorAll('script[type="application/ld+json"]');
  breadcrumbScripts.forEach(script => {
    try {
      const data = JSON.parse(script.textContent);
      if (data['@type'] === 'BreadcrumbList') {
        data.itemListElement = [
          {
            '@type': 'ListItem',
            position: 1,
            name: 'Home',
            item: BASE_URL + '/'
          },
          {
            '@type': 'ListItem',
            position: 2,
            name: meta.crumb,
            item: canonical
          }
        ];
        script.textContent = JSON.stringify(data, null, 2);
      }
    } catch (e) { /* skip non-JSON blocks */ }
  });
}

function setMetaContent(selector, content) {
  const el = document.querySelector(selector);
  if (el) el.setAttribute('content', content);
}

